import * as React from 'react';
import areEqualValues from './areEqualValues';

function hasOwnValueProp(child) {
  return Object.prototype.hasOwnProperty.call(child.props, 'value');
}

function getTextFromReactNode(node) {
  if (typeof node === 'string' || typeof node === 'number') {
    return String(node);
  }

  let text = '';

  React.Children.forEach(node, (child) => {
    if (typeof child === 'string' || typeof child === 'number') {
      text += String(child);
    } else if (React.isValidElement(child)) {
      text += getTextFromReactNode(child.props.children);
    }
  });

  return text;
}

export function getMatchingOptionIndex(options, search, startIndex = 0) {
  if (options.length === 0) {
    return -1;
  }

  const normalizedStartIndex = ((startIndex % options.length) + options.length) % options.length;

  for (let offset = 0; offset < options.length; offset += 1) {
    const index = (normalizedStartIndex + offset) % options.length;

    if (options[index].label.startsWith(search)) {
      return index;
    }
  }

  return -1;
}

export function canCycleRepeatedCharacter(options, key) {
  return !options.some((option) => option.label[0] === key && option.label[1] === key);
}

export function getTypeaheadOptions(childrenArray, value) {
  const options = [];
  let selectedIndex = -1;

  for (let index = 0; index < childrenArray.length; index += 1) {
    const child = childrenArray[index];

    if (!React.isValidElement(child) || !hasOwnValueProp(child) || child.props.disabled) {
      continue;
    }

    // Closed typeahead cannot exclude CSS-hidden text because no option DOM is mounted.
    const label = getTextFromReactNode(child.props.children).trim().toLowerCase();

    if (label === '') {
      continue;
    }

    if (selectedIndex === -1 && areEqualValues(value, child.props.value)) {
      selectedIndex = options.length;
    }

    options.push({
      child,
      label,
      value: child.props.value,
    });
  }

  return {
    options,
    selectedIndex,
  };
}

import { logger } from 'storybook/internal/client-logger';
import type { ArgTypesEnhancer, Renderer, SBType } from 'storybook/internal/types';

import { mapValues } from 'es-toolkit/object';
import { dedent } from 'ts-dedent';

import { combineParameters } from './parameters.ts';

const inferType = (
  value: any,
  name: string,
  visited: Set<any>,
  cache: Map<any, SBType>
): SBType => {
  const type = typeof value;
  switch (type) {
    case 'boolean':
    case 'string':
    case 'number':
    case 'function':
    case 'symbol':
      return { name: type };
    default:
      break;
  }
  if (value) {
    // Check cache first for previously computed results
    if (cache.has(value)) {
      return cache.get(value)!;
    }

    // Check for cycles (currently being processed in this path)
    if (visited.has(value)) {
      logger.warn(dedent`
        We've detected a cycle in arg '${name}'. Args should be JSON-serializable.

        Consider using the mapping feature or fully custom args:
        - Mapping: https://storybook.js.org/docs/writing-stories/args#mapping-to-complex-arg-values
        - Custom args: https://storybook.js.org/docs/essentials/controls#fully-custom-args
      `);
      return { name: 'other', value: 'cyclic object' };
    }

    visited.add(value);

    let result: SBType;

    if (Array.isArray(value)) {
      const childType: SBType =
        value.length > 0
          ? inferType(value[0], name, visited, cache)
          : { name: 'other', value: 'unknown' };
      result = { name: 'array', value: childType };
    } else {
      const fieldTypes = mapValues(value, (field) => inferType(field, name, visited, cache));
      result = { name: 'object', value: fieldTypes };
    }

    visited.delete(value); // Remove from current path after processing
    cache.set(value, result); // Cache the result for future lookups

    return result;
  }
  return { name: 'object', value: {} };
};

export const inferArgTypes: ArgTypesEnhancer<Renderer> = (context) => {
  const { id, argTypes: userArgTypes = {}, initialArgs = {} } = context;
  const cache = new Map<any, SBType>();
  const argTypes = mapValues(initialArgs, (arg, key) => ({
    name: key,
    type: inferType(arg, `${id}.${key}`, new Set(), cache),
  }));
  const userArgTypesNames = mapValues(userArgTypes, (argType, key) => ({
    name: key,
  }));
  return combineParameters(argTypes, userArgTypesNames, userArgTypes);
};

inferArgTypes.secondPass = true;

import { BroadcastChannel } from 'broadcast-channel'
import type { BroadcastChannelOptions } from 'broadcast-channel'
import type { QueryClient } from '@tanstack/query-core'

interface BroadcastQueryClientOptions {
  queryClient: QueryClient
  broadcastChannel?: string
  options?: BroadcastChannelOptions
}

export function broadcastQueryClient({
  queryClient,
  broadcastChannel = 'tanstack-query',
  options,
}: BroadcastQueryClientOptions): () => void {
  let transaction = false
  const tx = (cb: () => void) => {
    transaction = true
    cb()
    transaction = false
  }

  const channel = new BroadcastChannel(broadcastChannel, {
    webWorkerSupport: false,
    ...options,
  })

  const queryCache = queryClient.getQueryCache()

  const unsubscribe = queryClient.getQueryCache().subscribe((queryEvent) => {
    if (transaction) {
      return
    }

    const {
      query: { queryHash, queryKey, state, observers },
    } = queryEvent

    if (queryEvent.type === 'updated' && queryEvent.action.type === 'success') {
      channel.postMessage({
        type: 'updated',
        queryHash,
        queryKey,
        state,
      })
    }

    if (queryEvent.type === 'removed' && observers.length > 0) {
      channel.postMessage({
        type: 'removed',
        queryHash,
        queryKey,
      })
    }

    if (queryEvent.type === 'added') {
      channel.postMessage({
        type: 'added',
        queryHash,
        queryKey,
      })
    }
  })

  channel.onmessage = (action) => {
    if (!action?.type) {
      return
    }

    tx(() => {
      const { type, queryHash, queryKey, state } = action

      const query = queryCache.get(queryHash)

      if (type === 'updated') {
        if (query) {
          query.setState(state)
          return
        }

        queryCache.build(
          queryClient,
          {
            queryKey,
            queryHash,
          },
          state,
        )
      } else if (type === 'removed') {
        if (query) {
          queryCache.remove(query)
        }
      } else if (type === 'added') {
        if (query) {
          query.setState(state)
          return
        }
        queryCache.build(
          queryClient,
          {
            queryKey,
            queryHash,
          },
          state,
        )
      }
    })
  }
  return () => {
    unsubscribe()
    channel.close()
  }
}

