import { UsePopperOptions, Offset, Placement, Modifiers } from './usePopper';

export type Config = {
  flip?: boolean;
  fixed?: boolean;
  alignEnd?: boolean;
  enabled?: boolean;
  containerPadding?: number;
  arrowElement?: Element | null;
  enableEvents?: boolean;
  offset?: Offset;
  placement?: Placement;
  popperConfig?: UsePopperOptions;
};

export function toModifierMap(modifiers: Modifiers | undefined) {
  const result: Modifiers = {};

  if (!Array.isArray(modifiers)) {
    return modifiers || result;
  }

  // eslint-disable-next-line no-unused-expressions
  modifiers?.forEach((m) => {
    result[m.name!] = m;
  });
  return result;
}

export function toModifierArray(map: Modifiers | undefined = {}) {
  if (Array.isArray(map)) return map;
  return Object.keys(map).map((k) => {
    map[k].name = k;
    return map[k];
  });
}

export default function mergeOptionsWithPopperConfig({
  enabled,
  enableEvents,
  placement,
  flip,
  offset,
  fixed,
  containerPadding,
  arrowElement,
  popperConfig = {},
}: Config): UsePopperOptions {
  const modifiers = toModifierMap(popperConfig.modifiers);

  return {
    ...popperConfig,
    placement,
    enabled,
    strategy: fixed ? 'fixed' : popperConfig.strategy,
    modifiers: toModifierArray({
      ...modifiers,
      eventListeners: {
        enabled: enableEvents,
      },
      preventOverflow: {
        ...modifiers.preventOverflow,
        options: containerPadding
          ? {
              padding: containerPadding,
              ...modifiers.preventOverflow?.options,
            }
          : modifiers.preventOverflow?.options,
      },
      offset: {
        options: {
          offset,
          ...modifiers.offset?.options,
        },
      },
      arrow: {
        ...modifiers.arrow,
        enabled: !!arrowElement,
        options: {
          ...modifiers.arrow?.options,
          element: arrowElement,
        },
      },
      flip: {
        enabled: !!flip,
        ...modifiers.flip,
      },
    }),
  };
}

import { logger } from 'storybook/internal/client-logger';
import type {
  ArgTypesEnhancer,
  Renderer,
  SBEnumType,
  StrictInputType,
} from 'storybook/internal/types';

import { mapValues } from 'es-toolkit/object';

import { filterArgTypes } from './filterArgTypes.ts';
import { combineParameters } from './parameters.ts';

export type ControlsMatchers = {
  date: RegExp;
  color: RegExp;
};

const inferControl = (argType: StrictInputType, name: string, matchers: ControlsMatchers): any => {
  const { type, options } = argType;
  if (!type) {
    return undefined;
  }

  // args that end with background or color e.g. iconColor
  if (matchers.color && matchers.color.test(name)) {
    const controlType = type.name;

    if (controlType === 'string') {
      return { control: { type: 'color' } };
    }

    if (controlType !== 'enum') {
      logger.warn(
        `Addon controls: Control of type color only supports string, received "${controlType}" instead`
      );
    }
  }

  // args that end with date e.g. purchaseDate
  if (matchers.date && matchers.date.test(name)) {
    return { control: { type: 'date' } };
  }

  switch (type.name) {
    case 'array':
      return { control: { type: 'object' } };
    case 'boolean':
      return { control: { type: 'boolean' } };
    case 'string':
      return { control: { type: 'text' } };
    case 'number':
      return { control: { type: 'number' } };
    case 'enum': {
      const { value } = type as SBEnumType;
      return { control: { type: value?.length <= 5 ? 'radio' : 'select' }, options: value };
    }
    case 'function':
    case 'symbol':
      return null;
    default:
      return { control: { type: options ? 'select' : 'object' } };
  }
};

export const inferControls: ArgTypesEnhancer<Renderer> = (context) => {
  const {
    argTypes,
    parameters: { __isArgsStory, controls: { include = null, exclude = null, matchers = {} } = {} },
  } = context;

  if (!__isArgsStory) {
    return argTypes;
  }

  const filteredArgTypes = filterArgTypes(argTypes, include, exclude);
  const withControls = mapValues(filteredArgTypes, (argType, name) => {
    return argType?.type && inferControl(argType, name.toString(), matchers);
  });

  return combineParameters(withControls, filteredArgTypes);
};

inferControls.secondPass = true;

export const argTypesEnhancers = [inferControls];

import {
  type Dict,
  compact,
  isObject,
  isString,
  memo,
  mergeWith,
  walkObject,
} from "../utils"
import type { SystemStyleObject } from "./css.types"
import { EMPTY_OBJECT, createEmptyObject } from "./singleton"
import { sortAtRules } from "./sort-at-rules"
import type { SystemContext } from "./types"

const importantRegex = /\s*!(important)?/i

const isImportant = memo((v: unknown) =>
  isString(v) ? importantRegex.test(v) : false,
)

const withoutImportant = memo((v: unknown) =>
  isString(v) ? v.replace(importantRegex, "").trim() : v,
)

type CssFnOptions = Pick<SystemContext, "conditions"> & {
  normalize: (styles: Dict) => Dict
  transform: (prop: string, value: any) => Dict | undefined
}

export function createCssFn(context: CssFnOptions) {
  const { transform, conditions, normalize } = context
  const mergeFn = mergeCss(context)

  return memo(function cssFn(...styleArgs: SystemStyleObject[]) {
    const styles = mergeFn(...styleArgs)

    const normalized = normalize(styles)
    const result: Dict = createEmptyObject()

    walkObject(normalized, (value, paths) => {
      if (value == null) return

      const [prop, ...selectors] = conditions
        .sort(paths)
        .map(conditions.resolve)

      const important = isImportant(value)
      if (important) {
        value = withoutImportant(value)
      }

      let transformed = transform(prop, value) ?? EMPTY_OBJECT

      transformed = walkObject(
        transformed,
        (v) => (isString(v) && important ? `${v} !important` : v),
        { getKey: (prop) => conditions.expandAtRule(prop) },
      )

      mergeByPath(result, selectors.flat(), transformed)
    })

    return sortAtRules(result)
  })
}

function mergeByPath(target: Dict, paths: string[], value: Dict) {
  let acc = target
  for (const path of paths) {
    if (!path) continue
    if (!acc[path]) acc[path] = createEmptyObject()
    acc = acc[path]
  }
  mergeWith(acc, value)
}

function compactFn(...styles: Dict[]) {
  return styles.filter((style) => {
    if (!isObject(style)) return false
    const compacted = compact(style)
    const keys = Object.keys(compacted)
    return keys.length > 0
  })
}

function mergeCss(ctx: CssFnOptions) {
  function resolve(styles: Dict[]) {
    const comp = compactFn(...styles)
    if (comp.length === 1) return comp
    return comp.map((style) => ctx.normalize(style))
  }
  return memo(function mergeFn(...styles: Dict[]) {
    return mergeWith({}, ...resolve(styles))
  })
}

import type { Layout, RegisteredGroup } from "../../components/group/types";
import { formatLayoutNumber } from "./formatLayoutNumber";

export function preserveFixedPanelSizes({
  group,
  nextGroupSize,
  prevGroupSize,
  prevLayout
}: {
  group: RegisteredGroup;
  nextGroupSize: number;
  prevGroupSize: number;
  prevLayout: Layout;
}) {
  if (
    prevGroupSize <= 0 ||
    nextGroupSize <= 0 ||
    prevGroupSize === nextGroupSize
  ) {
    return prevLayout;
  }

  let fixedPanelsTotalSize = 0;
  let flexiblePanelsTotalPrevSize = 0;
  let hasPreservePixelSizePanels = false;

  const fixedPanels = new Map<string, number>();
  const flexiblePanelIds: string[] = [];

  for (const panel of group.panels) {
    const prevPanelSize = prevLayout[panel.id] ?? 0;
    switch (panel.panelConstraints.groupResizeBehavior) {
      case "preserve-pixel-size": {
        hasPreservePixelSizePanels = true;

        const prevPanelSizeInPixels = (prevPanelSize / 100) * prevGroupSize;
        const nextPanelSize = formatLayoutNumber(
          (prevPanelSizeInPixels / nextGroupSize) * 100
        );

        fixedPanels.set(panel.id, nextPanelSize);
        fixedPanelsTotalSize += nextPanelSize;
        break;
      }
      case "preserve-relative-size":
      default: {
        flexiblePanelIds.push(panel.id);
        flexiblePanelsTotalPrevSize += prevPanelSize;
        break;
      }
    }
  }

  if (!hasPreservePixelSizePanels || flexiblePanelIds.length === 0) {
    return prevLayout;
  }

  const remainingSize = 100 - fixedPanelsTotalSize;
  const nextLayout = { ...prevLayout };

  fixedPanels.forEach((size, panelId) => {
    nextLayout[panelId] = size;
  });

  if (flexiblePanelsTotalPrevSize > 0) {
    for (const panelId of flexiblePanelIds) {
      const prevSize = prevLayout[panelId] ?? 0;
      nextLayout[panelId] = formatLayoutNumber(
        (prevSize / flexiblePanelsTotalPrevSize) * remainingSize
      );
    }
  } else {
    const evenSize = formatLayoutNumber(
      remainingSize / flexiblePanelIds.length
    );
    for (const panelId of flexiblePanelIds) {
      nextLayout[panelId] = evenSize;
    }
  }

  return nextLayout;
}

import addImports from 'jscodeshift-add-imports';

export default function transformer(fileInfo, api, options) {
  const j = api.jscodeshift;
  const importModule = options.importModule || '@material-ui/core';
  const targetModule = options.targetModule || '@material-ui/core';

  const requirePath = importModule;

  // eslint-disable-next-line global-require, import/no-dynamic-require
  const whitelist = require(requirePath);

  const printOptions = options.printOptions || {
    quote: 'single',
    trailingComma: true,
  };

  const root = j(fileInfo.source);
  const importRegExp = new RegExp(`^${importModule}/(?:[^/]+/)*([^/]+)$`);

  const resultSpecifiers = [];

  root.find(j.ImportDeclaration).forEach((path) => {
    if (!path.node.specifiers.length) {
      return;
    }

    if (path.value.importKind && path.value.importKind !== 'value') {
      return;
    }
    const importPath = path.value.source.value;
    const match = importPath.match(importRegExp);
    if (!match) {
      return;
    }

    if (importPath.includes('internal/')) {
      return;
    }

    path.node.specifiers.forEach((specifier, index) => {
      if (specifier.importKind && specifier.importKind !== 'value') {
        return;
      }
      if (specifier.type === 'ImportNamespaceSpecifier') {
        return;
      }

      switch (specifier.type) {
        case 'ImportDefaultSpecifier': {
          const localName = specifier.local.name;
          const moduleName = match[1];
          if (whitelist[moduleName] == null) {
            return;
          }
          resultSpecifiers.push(
            j.importSpecifier(j.identifier(moduleName), j.identifier(localName)),
          );
          path.get('specifiers', index).prune();
          break;
        }
        case 'ImportSpecifier':
          if (
            whitelist[specifier.imported.name] == null &&
            specifier.imported.name !== 'withStyles'
          ) {
            return;
          }
          resultSpecifiers.push(specifier);
          path.get('specifiers', index).prune();
          break;
        default:
          break;
      }
    });

    if (!path.node.specifiers.length) {
      path.prune();
    }
  });

  if (resultSpecifiers.length) {
    addImports(root, j.importDeclaration(resultSpecifiers, j.stringLiteral(targetModule)));
  }

  return root.toSource(printOptions);
}

