import type { Layout, RegisteredGroup } from "../../components/group/types";
import type { PanelConstraints } from "../../components/panel/types";
import { EventEmitter } from "../../utils/EventEmitter";
import type { SeparatorToPanelsMap } from "./types";

type State = {
  defaultLayoutDeferred: boolean;
  derivedPanelConstraints: PanelConstraints[];
  groupSize: number;
  layout: Layout;
  separatorToPanels: SeparatorToPanelsMap;
};

export type MountedGroups = Map<RegisteredGroup, State>;

let map: MountedGroups = new Map();

type GroupChangeEvent = {
  group: RegisteredGroup;
  next: State;
  prev: State | undefined;
};
type GroupsChangeEvent = {
  next: MountedGroups;
  prev: MountedGroups;
};

const eventEmitter = new EventEmitter<{
  groupChange: GroupChangeEvent;
  groupsChange: GroupsChangeEvent;
}>();

export function deleteMutableGroup(group: RegisteredGroup) {
  map = new Map(map);
  map.delete(group);
}

export function getRegisteredGroup(
  groupId: string
): RegisteredGroup | undefined;
export function getRegisteredGroup(
  groupId: string,
  assert: true
): RegisteredGroup;
export function getRegisteredGroup(groupId: string, assert?: boolean) {
  for (const [group] of map) {
    if (group.id === groupId) {
      return group;
    }
  }

  if (assert) {
    throw Error(`Could not find data for Group with id ${groupId}`);
  }

  return undefined;
}

export function getMountedGroupState(groupId: string): State | undefined;
export function getMountedGroupState(groupId: string, assert: true): State;
export function getMountedGroupState(groupId: string, assert?: boolean) {
  for (const [group, mountedGroup] of map) {
    if (group.id === groupId) {
      return mountedGroup;
    }
  }

  if (assert) {
    throw Error(`Could not find data for Group with id ${groupId}`);
  }

  return undefined;
}

export function getMountedGroups() {
  return map;
}

export function subscribeToMountedGroup(
  groupId: string,
  callback: (event: GroupChangeEvent) => void
) {
  return eventEmitter.addListener("groupChange", (event) => {
    if (event.group.id === groupId) {
      callback(event);
    }
  });
}

export function updateMountedGroup(group: RegisteredGroup, next: State) {
  const prev = map.get(group);

  map = new Map(map);
  map.set(group, next);

  eventEmitter.emit("groupChange", {
    group,
    prev,
    next
  });
}

import fs from "node:fs/promises";

import * as Path from "pathe";
import { green, red } from "picocolors";
import type vite from "vite";

import { type Context, createContext } from "./context";
import {
  type VirtualFile,
  typesDirectory,
  generateFuture,
  generateRoutes,
  generateServerBuild,
} from "./generate";

async function clearRouteModuleAnnotations(ctx: Context) {
  await fs.rm(
    Path.join(typesDirectory(ctx), Path.basename(ctx.config.appDirectory)),
    { recursive: true, force: true },
  );
}

async function write(...files: Array<VirtualFile>) {
  return Promise.all(
    files.map(async ({ filename, content }) => {
      await fs.mkdir(Path.dirname(filename), { recursive: true });
      await fs.writeFile(filename, content);
    }),
  );
}

export async function run(
  rootDirectory: string,
  { mode, rsc }: { mode: string; rsc: boolean },
) {
  const ctx = await createContext({ rootDirectory, mode, rsc, watch: false });
  await fs.rm(typesDirectory(ctx), { recursive: true, force: true });
  await write(
    generateFuture(ctx),
    generateServerBuild(ctx),
    ...generateRoutes(ctx),
  );
}

export type Watcher = {
  close: () => Promise<void>;
};

export async function watch(
  rootDirectory: string,
  { mode, logger, rsc }: { mode: string; logger?: vite.Logger; rsc: boolean },
): Promise<Watcher> {
  const ctx = await createContext({ rootDirectory, mode, rsc, watch: true });
  await fs.rm(typesDirectory(ctx), { recursive: true, force: true });
  await write(
    generateFuture(ctx),
    generateServerBuild(ctx),
    ...generateRoutes(ctx),
  );
  logger?.info(green("generated types"), { timestamp: true, clear: true });

  ctx.configLoader.onChange(
    async ({ result, configChanged, routeConfigChanged }) => {
      if (!result.ok) {
        logger?.error(red(result.error), { timestamp: true, clear: true });
        return;
      }
      ctx.config = result.value;

      if (configChanged) {
        await write(generateFuture(ctx));
        logger?.info(green("regenerated types"), {
          timestamp: true,
          clear: true,
        });
      }

      if (routeConfigChanged) {
        await clearRouteModuleAnnotations(ctx);
        await write(...generateRoutes(ctx));
        logger?.info(green("regenerated types"), {
          timestamp: true,
          clear: true,
        });
      }
    },
  );

  return {
    close: async () => await ctx.configLoader.close(),
  };
}

import {TreeState} from './types'

export function _findPrevItemElement(
  state: TreeState,
  itemElements: HTMLElement[],
  focusedElement: HTMLElement,
): HTMLElement | null {
  const idx = itemElements.indexOf(focusedElement)
  const els = itemElements.slice(0, idx)
  const len = els.length

  for (let i = len - 1; i >= 0; i -= 1) {
    const itemKey = els[i].getAttribute('data-tree-key')

    if (!itemKey) {
      continue
    }

    const segments = itemKey.split('/')

    segments.pop()

    const p: string[] = []

    let expanded = true

    for (let j = 0; j < segments.length; j += 1) {
      p.push(segments[j])

      const k = p.join('/')

      if (!state[k]?.expanded) {
        expanded = false
        break
      }
    }

    if (expanded) {
      return els[i]
    }
  }

  return null
}

export function _findNextItemElement(
  state: TreeState,
  itemElements: HTMLElement[],
  focusedElement: HTMLElement,
): HTMLElement | null {
  const idx = itemElements.indexOf(focusedElement)
  const els = itemElements.slice(idx)
  const len = itemElements.length

  for (let i = 1; i < len; i += 1) {
    if (!els[i]) {
      continue
    }

    const itemKey = els[i].getAttribute('data-tree-key')

    if (!itemKey) {
      continue
    }

    const segments = itemKey.split('/')

    segments.pop()

    const p: string[] = []

    let expanded = true

    for (let j = 0; j < segments.length; j += 1) {
      p.push(segments[j])

      const k = p.join('/')

      if (!state[k]?.expanded) {
        expanded = false
        break
      }
    }

    if (expanded) {
      return els[i]
    }
  }

  return null
}

export function _focusItemElement(el: HTMLElement): void {
  if (el.getAttribute('role') === 'treeitem') {
    el.focus()
  }

  if (el.getAttribute('role') === 'none') {
    const firstChild = el.firstChild

    if (firstChild && firstChild instanceof HTMLElement) {
      firstChild.focus()
    }
  }
}
